!function(){"use strict";var t=document.getElementById("ltms-shipping-export-csv");t&&t.addEventListener("click",function(){var e=document.querySelectorAll(".ltms-table tbody tr"),n="Fecha,Pedido,Transportadora,Costo Absorbido,Costo Real\n";e.forEach(function(t){var e=t.querySelectorAll("td");if(e.length>=5){var o=Array.from(e).slice(0,5).map(function(t){return'"'+(t.textContent||"").trim().replace(/"/g,'""')+'"'}).join(",");n+=o+"\n"}});var o=new Blob([n],{type:"text/csv;charset=utf-8;"}),r=document.createElement("a");r.href=URL.createObjectURL(o),r.download=t.dataset.filename||"fletes.csv",r.click()}),document.querySelectorAll('[data-action="submit-form"]').forEach(function(t){t.addEventListener("change",function(){this.form.submit()})})}();